// ✅ GOOD - use an action filter when you need the bound action arguments
public class AuditOrderFilter : IActionFilter
{
    private readonly IAuditLog _auditLog;
    public AuditOrderFilter(IAuditLog auditLog) => _auditLog = auditLog;

    public void OnActionExecuting(ActionExecutingContext ctx)
    {
        var orderId = ctx.ActionArguments["orderId"];
        var user = ctx.HttpContext.User.Identity?.Name;
        _auditLog.Record($"Order {orderId} accessed by {user}");
    }
    public void OnActionExecuted(ActionExecutedContext ctx) { }
}

// ❌ BAD - putting caching in an action filter (model binding already ran, wasteful on cache hit)
public class CacheActionFilter : IActionFilter
{
    public void OnActionExecuting(ActionExecutingContext ctx)
    {
        // model binding already happened - work was done before we can return cache
    }
    public void OnActionExecuted(ActionExecutedContext ctx) { }
}

// ✅ GOOD - resource filter short-circuits before model binding on a cache hit
public class ProductCacheFilter : IResourceFilter
{
    private readonly IResponseCache _cache;
    public ProductCacheFilter(IResponseCache cache) => _cache = cache;

    public void OnResourceExecuting(ResourceExecutingContext ctx)
    {
        if (_cache.TryGet(ctx.HttpContext.Request.Path, out var cached))
            ctx.Result = cached; // skips binding and action entirely
    }
    public void OnResourceExecuted(ResourceExecutedContext ctx) { }
}

