// ✅ GOOD - correct HTTP status codes with structured problem details
[HttpPost]
public ActionResult<OrderConfirmation> PlaceOrder(OrderRequest request)
{
    if (!_inventory.HasStock(request.ProductId))
        return Conflict(new ProblemDetails { Title = "Product out of stock",
            Detail = $"ProductId {request.ProductId} has no available stock." });
    var order = _orderService.Create(request);
    return CreatedAtAction(nameof(GetOrder), new { id = order.Id }, order);
}

// ❌ BAD - allowing any origin with credentials is blocked by browsers and is a security risk
builder.Services.AddCors(o => o.AddPolicy("open",
    p => p.AllowAnyOrigin().AllowAnyHeader().AllowAnyMethod().AllowCredentials()));

// ✅ GOOD - locked down to the SPA's origin with explicit permissions
builder.Services.AddCors(o => o.AddPolicy("ShopFrontend",
    p => p.WithOrigins("https://shop.retailcorp.com")
           .WithMethods("GET", "POST", "PUT", "DELETE")
           .WithHeaders("Authorization", "Content-Type")
           .AllowCredentials()));

app.UseRouting();
app.UseCors("ShopFrontend");
app.UseAuthorization();

// ❌ BAD - role explosion to handle compound access rules
[Authorize(Roles = "AdminEMEA,ManagerEMEA,AdminAPAC,ManagerAPAC")]
public IActionResult GetRegionalSalesReport() { return Ok(); }

// ✅ GOOD - express the compound rule as a named policy
builder.Services.AddAuthorization(opts =>
    opts.AddPolicy("RegionalManager", policy => policy
        .RequireAuthenticatedUser()
        .RequireClaim("department", "Sales", "Finance")
        .AddRequirements(new RegionMatchRequirement())));

// Register the handler
builder.Services.AddSingleton<IAuthorizationHandler, RegionMatchHandler>();

[Authorize(Policy = "RegionalManager")]
public IActionResult GetRegionalSalesReport() { return Ok(); }

// ❌ BAD - long-lived access token with no refresh mechanism
var accessToken = GenerateJwt(user, expiry: DateTime.UtcNow.AddDays(30));
return Ok(new { accessToken });

// ✅ GOOD - short access token paired with a rotated refresh token in httpOnly cookie
var accessToken = GenerateJwt(user, expiry: DateTime.UtcNow.AddMinutes(10));
var refreshToken = await _tokenService.CreateRefreshTokenAsync(user.Id);
Response.Cookies.Append("refresh_token", refreshToken.Value,
    new CookieOptions
    {
        HttpOnly = true,
        Secure = true,
        SameSite = SameSiteMode.Strict,
        Expires = DateTimeOffset.UtcNow.AddDays(30)
    });
return Ok(new { accessToken });
